export function setNested(object, key, value) {
  let schema = object;
  let keys = key.split(".");
  let len = keys.length;
  for (let i = 0; i < len - 1; i++) {
    let elem = keys[i];
    if (!schema[elem]) schema[elem] = {};
    schema = schema[elem];
  }

  schema[keys[len - 1]] = value;
  return object;
}

export function getNested(object, key, default_) {
    //we have issue on the import because on of the new packages we upgraded pnpm, this is last time it was working without it: https://github.com/SallaApp/twilight/blob/0215beb4a1f89fb233df9b173134d7571882f5fe/pnpm-lock.yaml
    let data = lodashGet.default
    ? lodashGet.default(object, key)
    : lodashGet(object, key);
    return data !== undefined ? data : default_;
}

export function hasApplePay(): boolean {
  try {
    return !!window.ApplePaySession?.canMakePayments();// && !/snapchat/i.test(navigator.userAgent);
  } catch (error) {
    console.error(error);
    return false;
  }
}

export function isAppleDevice(): boolean {
  try {
    const ua = navigator.userAgent || '';
    const platform = navigator.platform || '';
    // Detect iOS devices
    const isIOS = /iPhone|iPad|iPod/i.test(ua);
    // Detect macOS
    const isMac = /Mac/i.test(platform);
    return isIOS || isMac;
  } catch (error) {
    console.error(error);
    return false;
  }
}

export function isIOSDevice(): boolean {
  try {
    const ua = navigator.userAgent || '';
    return /iPhone|iPad|iPod/i.test(ua);
  } catch (error) {
    console.error(error);
    return false;
  }
}

export function isIframe() {
  return window.self !== window.top
}


export function isPreview() {
  return isIframe()
}

/**
 * Factory function to create a wrapped object with proxy support
 */
export function createFormDataWrapper<T extends Record<string, any> | FormData>(
  data: T
): any {
  const wrapper = new FormDataWrapper(data);
  return wrapper.getProxy();
}

